(function () {
  function Sigma(graph, container) {
    this.graph = graph;
    this.container = container;
    this.handlers = {};
    var self = this;
    this.camera = {
      x: 0,
      y: 0,
      ratio: 1,
      animate: function (next) {
        this.x = next.x || this.x;
        this.y = next.y || this.y;
        this.ratio = next.ratio || this.ratio;
        self.refresh();
      },
    };

    this.canvas = document.createElement("canvas");
    this.canvas.style.width = "100%";
    this.canvas.style.height = "100%";
    this.canvas.style.display = "block";
    this.container.innerHTML = "";
    this.container.appendChild(this.canvas);
    this.ctx = this.canvas.getContext("2d");
    this._screenNodes = [];

    function resize() {
      var rect = self.container.getBoundingClientRect();
      self.canvas.width = Math.max(1, Math.floor(rect.width));
      self.canvas.height = Math.max(1, Math.floor(rect.height));
      self.refresh();
    }
    window.addEventListener("resize", resize);
    resize();

    this.canvas.addEventListener("click", function (event) {
      var rect = self.canvas.getBoundingClientRect();
      var x = event.clientX - rect.left;
      var y = event.clientY - rect.top;
      var hit = null;
      var best = Infinity;

      for (var i = 0; i < self._screenNodes.length; i++) {
        var n = self._screenNodes[i];
        var withinX = x >= n.x && x <= n.x + n.w;
        var withinY = y >= n.y && y <= n.y + n.h;
        if (withinX && withinY) {
          var cx = n.x + n.w / 2;
          var cy = n.y + n.h / 2;
          var dx = x - cx;
          var dy = y - cy;
          var d2 = dx * dx + dy * dy;
          if (d2 < best) {
            best = d2;
            hit = n;
          }
        }
      }

      if (hit && self.handlers.clickNode) {
        self.handlers.clickNode({ node: hit.id });
      }
    });

    var dragging = false;
    var lastX = 0;
    var lastY = 0;

    this.canvas.addEventListener("mousedown", function (event) {
      dragging = true;
      lastX = event.clientX;
      lastY = event.clientY;
      self.canvas.style.cursor = "grabbing";
    });
    window.addEventListener("mouseup", function () {
      dragging = false;
      self.canvas.style.cursor = "default";
    });
    window.addEventListener("mousemove", function (event) {
      if (!dragging) return;
      var dx = event.clientX - lastX;
      var dy = event.clientY - lastY;
      lastX = event.clientX;
      lastY = event.clientY;
      self.camera.x += dx;
      self.camera.y += dy;
      self.refresh();
    });
    this.canvas.addEventListener("wheel", function (event) {
      event.preventDefault();
      var rect = self.canvas.getBoundingClientRect();
      var mx = event.clientX - rect.left;
      var my = event.clientY - rect.top;
      var oldRatio = self.camera.ratio;
      var factor = event.deltaY > 0 ? 0.9 : 1.1;
      var newRatio = Math.max(0.35, Math.min(4.0, oldRatio * factor));
      if (newRatio === oldRatio) return;

      // Zoom around cursor point.
      self.camera.x = mx - ((mx - self.camera.x) / oldRatio) * newRatio;
      self.camera.y = my - ((my - self.camera.y) / oldRatio) * newRatio;
      self.camera.ratio = newRatio;
      self.refresh();
    }, { passive: false });
  }

  Sigma.prototype.on = function (evt, handler) {
    this.handlers[evt] = handler;
  };

  Sigma.prototype.getCamera = function () {
    return this.camera;
  };

  Sigma.prototype.refresh = function () {
    var ctx = this.ctx;
    if (!ctx) return;

    var nodes = [];
    this.graph._nodes.forEach(function (attrs, id) {
      if (attrs && attrs.node_type !== "__label__") {
        nodes.push({ id: id, attrs: attrs });
      }
    });

    var w = this.canvas.width;
    var h = this.canvas.height;
    ctx.clearRect(0, 0, w, h);

    if (nodes.length === 0) return;

    var pad = 30;
    var typeRank = {
      directory: 0,
      class: 1,
      method: 2,
      function: 3,
      virtual: 4
    };

    // Deterministic organized layout:
    // - columns by file_path
    // - rows by node_type, then stable index within each row
    var groups = {};
    for (var i = 0; i < nodes.length; i++) {
      var fp = String(nodes[i].attrs.file_path || "(virtual)");
      if (!groups[fp]) groups[fp] = [];
      groups[fp].push(nodes[i]);
    }

    var groupKeys = Object.keys(groups).sort();
    var groupIndexByKey = {};
    for (var gi = 0; gi < groupKeys.length; gi++) groupIndexByKey[groupKeys[gi]] = gi;

    var nodeScreenPos = new Map();
    var cols = Math.max(1, groupKeys.length);
    var colW = Math.max(180, Math.floor((w - pad * 2) / cols));
    var rowH = 64;

    for (var g = 0; g < groupKeys.length; g++) {
      var key = groupKeys[g];
      var bucket = groups[key];
      bucket.sort(function (a, b) {
        var ta = typeRank[a.attrs.node_type] !== undefined ? typeRank[a.attrs.node_type] : 99;
        var tb = typeRank[b.attrs.node_type] !== undefined ? typeRank[b.attrs.node_type] : 99;
        if (ta !== tb) return ta - tb;
        var la = String(a.attrs.label || a.id);
        var lb = String(b.attrs.label || b.id);
        return la.localeCompare(lb);
      });

      var rowOffsets = {};
      for (var n = 0; n < bucket.length; n++) {
        var node = bucket[n];
        var rank = typeRank[node.attrs.node_type] !== undefined ? typeRank[node.attrs.node_type] : 6;
        rowOffsets[rank] = (rowOffsets[rank] || 0) + 1;
        var offset = rowOffsets[rank] - 1;

        var sx = pad + g * colW + Math.min(colW - 30, 20 + offset * 16);
        var sy = pad + rank * rowH + offset * 18;
        nodeScreenPos.set(node.id, { sx: sx, sy: sy });
      }
    }

    this._screenNodes = [];
    var labelFont = "14px sans-serif";
    ctx.font = labelFont;

    function roundRect(x, y, w, h, r) {
      var radius = Math.min(r, w / 2, h / 2);
      ctx.beginPath();
      ctx.moveTo(x + radius, y);
      ctx.lineTo(x + w - radius, y);
      ctx.quadraticCurveTo(x + w, y, x + w, y + radius);
      ctx.lineTo(x + w, y + h - radius);
      ctx.quadraticCurveTo(x + w, y + h, x + w - radius, y + h);
      ctx.lineTo(x + radius, y + h);
      ctx.quadraticCurveTo(x, y + h, x, y + h - radius);
      ctx.lineTo(x, y + radius);
      ctx.quadraticCurveTo(x, y, x + radius, y);
      ctx.closePath();
    }

    for (var j = 0; j < nodes.length; j++) {
      var node = nodes[j];
      var a = node.attrs;
      var pos = nodeScreenPos.get(node.id) || { sx: pad + 20, sy: pad + 20 };
      var sx = pos.sx;
      var sy = pos.sy;
      var label = a.label || node.id.split("::").pop();
      var text = String(label);
      var textWidth = ctx.measureText(text).width;
      var boxW = Math.max(84, textWidth + 24);
      var boxH = 30;
      var x = sx - boxW / 2;
      var y = sy - boxH / 2;
      x = x * this.camera.ratio + this.camera.x;
      y = y * this.camera.ratio + this.camera.y;
      boxW *= this.camera.ratio;
      boxH *= this.camera.ratio;

      roundRect(x, y, boxW, boxH, 6);
      ctx.fillStyle = a.color || "#2563eb";
      ctx.fill();

      ctx.lineWidth = 1;
      ctx.strokeStyle = "rgba(15, 23, 42, 0.35)";
      ctx.stroke();

      ctx.fillStyle = "#ffffff";
      ctx.font = labelFont;
      ctx.fillText(text, x + 12 * this.camera.ratio, y + 20 * this.camera.ratio);

      this._screenNodes.push({ id: node.id, x: x, y: y, w: boxW, h: boxH });
    }

    // Draw edges after node boxes so lines remain visible and simple.
    this.graph._edges.forEach(function (edge) {
      var fromNode = null;
      var toNode = null;
      for (var i = 0; i < this._screenNodes.length; i++) {
        var n = this._screenNodes[i];
        if (n.id === edge.from) fromNode = n;
        if (n.id === edge.to) toNode = n;
        if (fromNode && toNode) break;
      }
      if (!fromNode || !toNode) return;

      var x1 = fromNode.x + fromNode.w / 2;
      var y1 = fromNode.y + fromNode.h / 2;
      var x2 = toNode.x + toNode.w / 2;
      var y2 = toNode.y + toNode.h / 2;

      ctx.strokeStyle = "rgba(31, 26, 22, 0.35)";
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.stroke();

      // Arrowhead
      var angle = Math.atan2(y2 - y1, x2 - x1);
      var headLen = 7;
      var ax = x2 - Math.cos(angle) * 10;
      var ay = y2 - Math.sin(angle) * 10;
      ctx.fillStyle = "rgba(31, 26, 22, 0.45)";
      ctx.beginPath();
      ctx.moveTo(ax, ay);
      ctx.lineTo(
        ax - headLen * Math.cos(angle - Math.PI / 6),
        ay - headLen * Math.sin(angle - Math.PI / 6)
      );
      ctx.lineTo(
        ax - headLen * Math.cos(angle + Math.PI / 6),
        ay - headLen * Math.sin(angle + Math.PI / 6)
      );
      ctx.closePath();
      ctx.fill();
    }, this);
  };

  window.Sigma = Sigma;
})();
